## Cursor-Based Pagination Implementation

### Helper Functions

```javascript
/**
 * Encodes a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * Uses base64url (RFC 4648 §5) to avoid +, /, = characters that break query strings.
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        // Normalize to ISO-8601 string regardless of whether pg returned a Date object or string
        created_at: created_at instanceof Date ? created_at.toISOString() : created_at,
        id,
    });
    return Buffer.from(payload)
        .toString('base64')
        .replace(/\+/g, '-')   // base64url: + → -
        .replace(/\//g, '_')   //             / → _
        .replace(/=/g, '');    //           strip padding
}

/**
 * Decodes a cursor string back to { created_at: string, id }.
 * Returns null for any malformed input — caller must treat null as a 400.
 */
function decodeCursor(cursorStr) {
    try {
        // Restore standard base64 from base64url before decoding
        const base64 = cursorStr
            .replace(/-/g, '+')
            .replace(/_/g, '/');

        const payload = Buffer.from(base64, 'base64').toString('utf8');
        const parsed  = JSON.parse(payload);

        // Both fields must be present
        if (parsed.created_at == null || parsed.id == null) return null;

        // Validate that created_at is actually a parseable timestamp
        const ts = new Date(parsed.created_at);
        if (isNaN(ts.getTime())) return null;

        return { created_at: ts.toISOString(), id: parsed.id };
    } catch {
        // JSON.parse failure, Buffer decoding error, etc.
        return null;
    }
}
```

